```verilog
module shifter (
	val,
	sham,
	out
);
	input wire [31:0] val;
	input wire [4:0] sham;
	output wire [31:0] out;
        wire [32:0] extend = { val, 1'b0 };
	assign out = {extend << sham}[32:1];
endmodule
```

```cpp
#include <verilated.h>
#include <verilated_vcd_c.h>

#include "Vshifter.h"
#include "Vshifter___024unit.h"

int main(int argc, char *argv[]) {
    Vshifter dut;
    int sim_time = 0;

    Verilated::traceEverOn(true);
    VerilatedVcdC *m_trace = new VerilatedVcdC;
    dut.trace(m_trace, 2);
    m_trace->open("waveform.vcd");

    dut.val = 0xdeadbeef;
    dut.sham = 0x30;
    dut.eval();
    m_trace->dump(0);
    printf("output: %x\n", dut.out);
    m_trace->close();
    return 0;
}
```

sham is 5-bit wide, so when 0x30 is passed to it, one would expect the lower 5 bits to be passed and the higher bits to be discarded. But it prints 0, which makes me think it's using all bits to do the shift. I can't be sure though, because the waveform shows sham as 0x10 as expected, but out is 0!.

Also, if I removed the `extend` variable and directly shift `val` the problem doesn't seem to occur.
